import React, { useMemo, useRef, useCallback, useEffect, Children } from 'react';
import PropTypes from 'prop-types';
import { useListBox } from '@react-aria/listbox';
import { useListState, useSingleSelectListState } from '@react-stately/list';
import { mergeProps } from '@react-aria/utils';
import useChildrenAdapter from '../hooks/useChildrenAdapter';
import { hasTouchSupport } from '@andes/common/build/utils/isMobile';
import { List } from '@andes/list';
import ListBoxGroup from './ListBoxGroup';
import ListBoxItem from './ListBoxItem';

import isSupportedGroupType from '../utils/isSupportedGroupType';
import isSupportedItemType from '../utils/isSupportedItemType';
import { findItemInChildren } from '../utils/findItemInChildren';
import { createMouseEventForElement } from '../utils/createMouseEventForElement';

/**
 * @typedef {React.RefObject<{
 * event?: React.MouseEvent<HTMLLIElement> | React.KeyboardEvent<HTMLLIElement>,
 * values?: string[],
 * itemDetails?: ItemDetail}>
 * } SelectedManagerRef
 */

/**
 * @typedef {Object} ItemDetail
 * @prop {string} value
 */

/** @typedef {import('./ListBoxItem').ListBoxItemChildrenItem} ListBoxItemProp */

/** @typedef {import('./ListBoxGroup').ListBoxGroupProp} ListBoxGroupProp */

/** @type {typeof import ('../..').ListBox} */
const ListBox = ({ ref, ...props }) => {
  const {
    children,
    id,
    selectionComponent,
    selectionMode = 'single',
    isRadioList = false,
    defaultSelectedKeys,
    selectedKeys,
    onClick,
    onSelect,
    shouldUseVirtualFocus,
    srLabel,
    ...other
  } = props;

  /** @type {React.RefObject<HTMLUListElement | null>} */
  const listSelectionRef = useRef(null);

  /** @type {SelectedManagerRef} */
  const selectedManager = useRef({});

  /** @type {React.MutableRefObject<Array<string>>} */
  const prevState = useRef(selectedKeys || defaultSelectedKeys || []);

  /**
   * Tracks the actual pointer type of the last interaction ('mouse', 'touch', 'pen').
   * Using navigator.maxTouchPoints to detect touch is incorrect — it reflects hardware
   * capability (static OS property), not the current input method. On Windows 10/11
   * machines with touchscreens, maxTouchPoints > 0 even when using a mouse, causing
   * mouse clicks to be treated as touch events and breaking selection in Dropdown.
   * @type {React.MutableRefObject<string>}
   */
  const lastPointerType = useRef('mouse');

  const handlePointerDown = useCallback((/** @type {PointerEvent} */ e) => {
    lastPointerType.current = e.pointerType || 'mouse';
  }, []);

  useEffect(() => {
    const resolvedRef = typeof ref === 'function' ? listSelectionRef : (ref || listSelectionRef);
    const el = resolvedRef.current;
    if (!el) return undefined;
    el.addEventListener('pointerdown', handlePointerDown);
    return () => el.removeEventListener('pointerdown', handlePointerDown);
  }, [handlePointerDown, ref]);

  const callOnSelectCallback = () => {
    const { event, values, itemDetails } = selectedManager.current;
    if (event && values && itemDetails) {
      if (typeof onSelect === 'function') onSelect(event, values, itemDetails);
      selectedManager.current = {};
    }
  };

  /**
   * @param {React.MouseEvent<HTMLLIElement> | React.KeyboardEvent<HTMLLIElement>} event
   * @param {ItemDetail} itemDetails
   */
  const onItemSelect = (event, itemDetails) => {
    selectedManager.current.event = event;
    selectedManager.current.itemDetails = itemDetails;
    callOnSelectCallback();
  };

  const getIdsAndDisabledKeys = () => {
    const disabledKeys = /** @type {string[]} */ ([]);
    const listItemsIds = /** @type {string[]} */ ([]);

    Children.forEach(children, (/** @type {React.ReactElement} */ child) => {
      if (isSupportedGroupType(child)) {
        Children.forEach(child.props.children, item => {
          listItemsIds.push(`${id}-option-${item.props.value}`);

          if (item.props?.disabled || item.props?.disableSelectionComponent) disabledKeys.push(item.props.value);
        });
      }

      if (isSupportedItemType(child)) {
        if (child.props?.disabled || child.props?.disableSelectionComponent) disabledKeys.push(child.props.value);
      }
    });

    return { disabledKeys, listItemsIds: listItemsIds.join(' ') };
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  const { disabledKeys, listItemsIds } = useMemo(() => getIdsAndDisabledKeys(), [children]);

  // Replaces ListItem with ListOption to prevent passing a generator and allows using forwardRef
  const adaptedChildren = useChildrenAdapter(children);

  /** @param {string | Set<string> | null} values */
  const handleSelectionChangeForTouchDevices = (values) => {
    const prevKeys = /** @type {Array<string>} */ (prevState.current);
    const newKeys = values ? [...values] : [];
    let itemKey = '';
    if (selectionMode === 'single') {
      if (newKeys.length > 0) {
        prevState.current = newKeys;
        [itemKey] = newKeys;
      } else {
        [itemKey] = prevKeys;
      }
    } else {
      const addedKeys = newKeys.filter(key => !prevKeys.includes(key));
      const removeKeys = prevKeys.filter(key => !newKeys.includes(key));
      itemKey = addedKeys.length > 0 ? addedKeys[0] : removeKeys[0];
      prevState.current = newKeys;
    }

    const itemElement = /** @type {React.RefObject<HTMLUListElement>} */ (ref || listSelectionRef)?.current?.querySelector?.(`li[data-key="${itemKey}"]`);

    if (!itemElement) return;

    const itemObject = findItemInChildren(adaptedChildren, itemKey);
    const itemValue = itemObject?.props?.value;
    const clickEvent = createMouseEventForElement(/** @type {HTMLLIElement} */(itemElement));

    if (typeof onClick === 'function') {
      onClick(
        /** @type {React.MouseEvent<HTMLLIElement>} */(/** @type {unknown} */ (clickEvent)),
        itemValue,
      );
    }

    if (typeof onSelect === 'function') {
      onSelect(
        /** @type {React.MouseEvent<HTMLLIElement>} */(/** @type {unknown} */ (clickEvent)),
        newKeys,
        { value: itemValue },
      );
    }

    if (typeof itemObject?.props?.onSelect === 'function') {
      itemObject.props.onSelect(clickEvent, { value: itemValue });
    }
  };

  /** @param {string | Set<string> | null} values */
  const onSelectionChanged = (values) => {
    if (hasTouchSupport() && lastPointerType.current === 'touch') {
      handleSelectionChangeForTouchDevices(values);
      return;
    }

    selectedManager.current.values = Array.from(values || []);
    callOnSelectCallback();
  };

  const listStateHook = isRadioList ? useSingleSelectListState : useListState;
  const state = listStateHook({
    disabledKeys,
    selectionMode,
    ...props,
    onSelectionChange: /** @type {(values: React.Key | Set<React.Key> | null) => void} */ (onSelectionChanged),
    children: adaptedChildren,
  });

  const { listBoxProps } = useListBox(
    {
      'aria-label': srLabel,
      disallowEmptySelection: true,
      disabledKeys,
      selectionMode,
      ...props,
      shouldUseVirtualFocus,
    },
    state,
    /** @type {React.RefObject<HTMLElement>} */(ref || listSelectionRef),
  );

  return (
    <List
      aria-owns={listItemsIds.length ? listItemsIds : undefined}
      srLabel={srLabel}
      component="ul"
      // @ts-expect-error: internal props
      listType="listbox"
      {...mergeProps(other, listBoxProps)}
      ref={ref || listSelectionRef}
      /* FIX-ME: when aria-label is removed from List. This is needed if not an error is thrown for using the prop,
      and useListBox needs this prop or else, throws a warning */
      aria-label={undefined}
    >
      {[...state.collection].map(listSelectNode => {
        const commonProps = {
          key: listSelectNode.key,
          state,
          selectionComponent,
          ...(hasTouchSupport() && lastPointerType.current === 'touch'
            ? {}
            : {
              onClick,
              /**
               * @param {React.MouseEvent<HTMLLIElement> | React.KeyboardEvent<HTMLLIElement>} event
               * @param {ItemDetail} itemDetails
               */
              onSelect: (event, itemDetails) => {
                if (typeof onItemSelect === 'function') onItemSelect(event, itemDetails);
                // @ts-expect-error
                // listSelectNode is an object according to the definition of the lib's hook, TS doesn't recognizes onSelect
                if (typeof listSelectNode.onSelect === 'function') listSelectNode.onSelect(event, itemDetails);
              },
            }
          ),
        };

        return listSelectNode.type === 'item'
          ? (<ListBoxItem
              item={/** @type {ListBoxItemProp} */ (listSelectNode)}
              {...commonProps}
              key={listSelectNode.key}
          />)
          : (<ListBoxGroup
              group={/** @type {ListBoxGroupProp} */ (listSelectNode)}
              {...commonProps}
              listId={id}
              key={listSelectNode.key}
          />);
      })}
    </List>
  );
};

ListBox.propTypes = {
  children: PropTypes.oneOfType([PropTypes.element, PropTypes.arrayOf(PropTypes.element.isRequired)]).isRequired,
  defaultSelectedKeys: PropTypes.arrayOf(PropTypes.string.isRequired),
  id: PropTypes.string.isRequired,
  isRadioList: PropTypes.bool,
  onClick: PropTypes.func,
  onSelect: PropTypes.func,
  selectedKeys: PropTypes.arrayOf(PropTypes.string.isRequired),
  selectionComponent: PropTypes.element,
  selectionMode: PropTypes.oneOf(['single', 'multiple']),
  shouldUseVirtualFocus: PropTypes.bool,
  srLabel: PropTypes.string,
};

ListBox.displayName = 'ListBox';

export default ListBox;
