/** @param {HTMLLIElement} element */
export const createMouseEventForElement = (element) => {
  const target = element ? Object.assign(element, {
    value: undefined,
  }) : {};

  const clickEvent = new MouseEvent('click', {
    bubbles: true,
    cancelable: true,
    view: window,
  });

  Object.defineProperty(clickEvent, 'target', {
    get: () => target,
  });

  return clickEvent;
};
